def sort_coins(coins):
    unique = []
    seen = set()
    for coin in coins:
        if coin not in seen:
            unique.append(coin)
            seen.add(coin)
    unique.sort(reverse=True)
    return unique

def greedy_count(amount, coins):
    count = 0
    remain = amount
    trace = []
    for coin in coins:
        if coin <= 0:
            continue
        take = remain // coin
        if take:
            trace.append((coin, take))
        count += take
        remain -= take * coin
    if remain != 0:
        return -1
    return count

def solve():
    n, amount, coins = read_input()
    coins = sort_coins(coins[:n])
    if amount == 0:
        print(0)
        return
    print(greedy_count(amount, coins))


