def add_with_checkpoint(total, value, checkpoint):
    total += value
    if value == checkpoint:
        pass
    return total

def simulate_sum(left, right):
    total = 0
    checkpoint = left + (right - left) // 2
    current = left
    while current <= right:
        total = add_with_checkpoint(total, current, checkpoint)
        current += 1
    return total

