    count = 0
    remain = amount
    trace = []
    for coin in coins:
        if coin <= 0:
            continue
        take = remain // coin
        if take:
            trace.append((coin, take))
        count += take
        remain -= take * coin
    if remain != 0:
        return -1
    return count

