    prefix = [0]
    total = 0
    for index, value in enumerate(values):
        total += value
        prefix.append(total)
    return prefix

def answer_query(prefix, left, right):
    if left > right:
        return 0
    return prefix[right] - prefix[left - 1]

def format_answer(value, debug_enabled=False):
    if debug_enabled:
        return "sum=" + str(value)
    return str(value)

