def find_next_one(values, start):
    index = start
    while index < len(values) and values[index] == 0:
        index += 1
    return index

def move_zeroes(values):
    i = 0
    while i < len(values):
        if values[i] == 0:
            j = find_next_one(values, i + 1)
            if j < len(values):
                values[i], values[j] = values[j], values[i]
                i += 1
            else:
                break
        i += 1
    return values

